import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './Navbar'; // This is your Sidebar
import Dashboard from './Dashboard';
import Uploads from './Uploads';
import Emissions from './Emissions';
import Sinks from './Sinks';
import Compare from './Compare';
import Pathways from './Pathways';
import Reports from './Reports';
import Login from './Login';
import Signup from './Signup';
import Account from './Account'; // Keep this for the profile page content

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    const userId = localStorage.getItem('userId');
    if (userId) setIsAuthenticated(true);
  }, []);

  const handleLogin = (id) => {
    localStorage.setItem('userId', id);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('userId');
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div style={{ display: 'flex' }}>
        {isAuthenticated && <Navbar onLogout={handleLogout} />} {/* restoring onLogout prop */}
        
        <div style={{ flex: 1, backgroundColor: '#f5f7fa', overflowY: 'auto', height: '100vh' }}>
          <Routes>
            <Route path="/login" element={!isAuthenticated ? <Login onLogin={handleLogin} /> : <Navigate to="/dashboard" />} />
            <Route path="/signup" element={!isAuthenticated ? <Signup onLogin={handleLogin} /> : <Navigate to="/dashboard" />} />
            
            {isAuthenticated ? (
              <>
                <Route path="/dashboard" element={<Dashboard />} />
                <Route path="/uploads" element={<Uploads />} />
                <Route path="/emissions" element={<Emissions />} />
                <Route path="/sinks" element={<Sinks />} />
                <Route path="/compare" element={<Compare />} />
                <Route path="/pathways" element={<Pathways />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="/profile" element={<Account />} />
                <Route path="*" element={<Navigate to="/dashboard" />} />
              </>
            ) : (
              <Route path="*" element={<Navigate to="/login" />} />
            )}
          </Routes>
        </div>
      </div>
    </Router>
  );
};

export default App;
